import React, { useState } from 'react';

const App = () => {
  const [energyConsumption, setEnergyConsumption] = useState({ current: 0, total: 0 });
  const [selectedCategory, setSelectedCategory] = useState('electricity');
  const categories = ['electricity', 'gas', 'water'];

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 w-full max-w-md">
        <h2 className="text-2xl font-bold mb-4">Energy Consumption Dashboard</h2>
        <div className="flex items-center mb-4">
          <button className="bg-[#C06C88] px-4 py-2 rounded-md mr-2" onClick={() => setSelectedCategory(categories[0])}>Electricity</button>
          <button className="bg-[#C06C88] px-4 py-2 rounded-md mr-2" onClick={() => setSelectedCategory(categories[1])}>Gas</button>
          <button className="bg-[#C06C88] px-4 py-2 rounded-md mr-2" onClick={() => setSelectedCategory(categories[2])}>Water</button>
        </div>
        <div className="flex items-center mb-4">
          <p className="text-lg mr-4">Current Energy Consumption: {energyConsumption.current} kWh</p>
          <button className="bg-[#B7D7CD] px-4 py-2 rounded-md" onClick={() => setEnergyConsumption({ ...energyConsumption, current: energyConsumption.current + 1 })}>Increment</button>
        </div>
        <div className="flex items-center mb-4">
          <p className="text-lg mr-4">Total Energy Consumption: {energyConsumption.total} kWh</p>
          <button className="bg-[#B7D7CD] px-4 py-2 rounded-md" onClick={() => setEnergyConsumption({ ...energyConsumption, total: energyConsumption.total + 1 })}>Increment</button>
        </div>
      </div>
    </div>
  );
};

export default App;
